#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <vector>
#include <string>
#include "cJSON.h"
#include "lodepng.h"

static std::vector<std::vector<double>> getMat(cJSON* root, const char* key) {
    cJSON* a = cJSON_GetObjectItemCaseSensitive(root, key);
    std::vector<std::vector<double>> m;
    cJSON* row;
    cJSON_ArrayForEach(row, a) {
        std::vector<double> r;
        cJSON* v;
        cJSON_ArrayForEach(v, row) r.push_back(v->valuedouble);
        m.push_back(r);
    }
    return m;
}
static std::vector<double> getVec(cJSON* root, const char* key) {
    cJSON* a = cJSON_GetObjectItemCaseSensitive(root, key);
    std::vector<double> r;
    cJSON* v;
    cJSON_ArrayForEach(v, a) r.push_back(v->valuedouble);
    return r;
}

// y = W x + b, with ReLU optional
static std::vector<double> linear(const std::vector<std::vector<double>>& W,
                                  const std::vector<double>& b,
                                  const std::vector<double>& x, bool relu) {
    std::vector<double> y(W.size());
    for (size_t i = 0; i < W.size(); ++i) {
        double s = b[i];
        const std::vector<double>& wi = W[i];
        for (size_t j = 0; j < wi.size(); ++j) s += wi[j] * x[j];
        if (relu && s < 0) s = 0;
        y[i] = s;
    }
    return y;
}

int main(int argc, char** argv) {
    if (argc < 3) { fprintf(stderr, "usage: %s weights.json image.png\n", argv[0]); return 1; }

    // read weights.json
    FILE* f = fopen(argv[1], "rb");
    if (!f) { fprintf(stderr, "cannot open %s\n", argv[1]); return 1; }
    fseek(f, 0, SEEK_END); long sz = ftell(f); fseek(f, 0, SEEK_SET);
    std::string buf(sz, 0);
    if (fread(&buf[0], 1, sz, f) != (size_t)sz) { fclose(f); return 1; }
    fclose(f);
    cJSON* root = cJSON_Parse(buf.c_str());
    if (!root) { fprintf(stderr, "json parse error\n"); return 1; }

    auto W1 = getMat(root, "input_layer.weight");  auto b1 = getVec(root, "input_layer.bias");
    auto W2 = getMat(root, "hidden_layer.weight"); auto b2 = getVec(root, "hidden_layer.bias");
    auto W3 = getMat(root, "output_layer.weight"); auto b3 = getVec(root, "output_layer.bias");

    // decode PNG as grayscale 8-bit
    std::vector<unsigned char> img;
    unsigned w, h;
    unsigned err = lodepng::decode(img, w, h, argv[2], LCT_GREY, 8);
    if (err) { fprintf(stderr, "png decode error %u: %s\n", err, lodepng_error_text(err)); return 1; }

    std::vector<double> x(w * h);
    for (size_t i = 0; i < img.size(); ++i) x[i] = img[i] / 255.0;

    auto h1 = linear(W1, b1, x, true);
    auto h2 = linear(W2, b2, h1, true);
    auto out = linear(W3, b3, h2, false);

    int best = 0;
    for (size_t i = 1; i < out.size(); ++i) if (out[i] > out[best]) best = i;

    printf("%d\n", best);
    cJSON_Delete(root);
    return 0;
}

